// src/components/Articles.js
import React, { useState } from 'react';

const mockArticles = [
  { id: 1, title: 'AI Trends 2025', status: 'New', notes: '' },
  { id: 2, title: 'Generative Models in Healthcare', status: 'Reviewed', notes: 'Promising use cases' },
  { id: 3, title: 'Transformer Architectures', status: 'In Progress', notes: '' },
];

const Articles = () => {
  const [search, setSearch] = useState('');
  const [articles, setArticles] = useState(mockArticles);
  const [selectedIds, setSelectedIds] = useState([]);

  const toggleSelect = (id) => {
    setSelectedIds(prev =>
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const handleNoteChange = (id, note) => {
    setArticles(prev => prev.map(a => a.id === id ? { ...a, notes: note } : a));
  };

  const updateStatus = (status) => {
    setArticles(prev => prev.map(a =>
      selectedIds.includes(a.id) ? { ...a, status } : a
    ));
  };

  const filtered = articles.filter(a => a.title.toLowerCase().includes(search.toLowerCase()));

  return (
    <div>
      <h2 className="text-xl font-bold mb-4">Articles</h2>
      <input
        type="text"
        placeholder="Search articles..."
        className="border p-2 mb-4 w-full"
        value={search}
        onChange={e => setSearch(e.target.value)}
      />
      <div className="flex gap-2 mb-2">
        <button className="bg-blue-500 text-white px-3 py-1 rounded" onClick={() => updateStatus('Reviewed')}>Mark as Reviewed</button>
        <button className="bg-green-500 text-white px-3 py-1 rounded" onClick={() => updateStatus('In Progress')}>Mark In Progress</button>
      </div>
      <table className="w-full bg-white shadow rounded">
        <thead>
          <tr className="bg-gray-100">
            <th className="p-2">Select</th>
            <th className="p-2">Title</th>
            <th className="p-2">Status</th>
            <th className="p-2">Notes</th>
          </tr>
        </thead>
        <tbody>
          {filtered.map(article => (
            <tr key={article.id}>
              <td className="p-2 text-center">
                <input type="checkbox" checked={selectedIds.includes(article.id)} onChange={() => toggleSelect(article.id)} />
              </td>
              <td className="p-2">{article.title}</td>
              <td className="p-2">{article.status}</td>
              <td className="p-2">
                <input
                  className="border px-2 py-1 w-full"
                  value={article.notes}
                  onChange={(e) => handleNoteChange(article.id, e.target.value)}
                />
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default Articles;
